private fun <T> Collection<Node<T>>.sort(): List<Node<T>> {
  val visited = mutableListOf<Node<T>>()
  val result = mutableListOf<Node<T>>()

  fun visit(node: Node<T>) {
    visited.add(node)
    node.dependencies.forEach {
      if (!visited.contains(it)) {
        visit(it)
      } else if (!result.contains(it)){
        throw IllegalArgumentException("Apollo: circular dependency detected on transform '${node.id}': ${visited.map { it.id } + node.id}")
      }
    }
    result.add(node)
  }

  forEach {
    if (!visited.contains(it)) {
      visit(it)
    }
  }
  return result
}

private fun BooleanExpression<BTerm>.toMap(): Map<String, Any> {
  val operator = when (this) {
    is BooleanExpression.And -> "and"
    is BooleanExpression.Or -> "or"
    is BooleanExpression.Not -> "not"
    is BooleanExpression.Element -> "element"
    BooleanExpression.False -> "false"
    BooleanExpression.True -> "true"
  }

  val operands = when (this) {
    is BooleanExpression.And -> operands.toList().map { it.toMap() }
    is BooleanExpression.Or -> operands.toList().map { it.toMap() }
    is BooleanExpression.Not -> listOf(operand.toMap())
    else -> emptyList()
  }

  val element = when (this) {
    is BooleanExpression.Element -> {
      this.value.toMap()
    }

    else -> emptyMap()
  }

  return mapOf(
      "operator" to operator,
      "operands" to operands,
      "element" to element
  )
}

public inline fun <A, B> Either<A, B>.combine(other: Either<A, B>, combineLeft: (A, A) -> A, combineRight: (B, B) -> B): Either<A, B> {
  contract {
    callsInPlace(combineLeft, InvocationKind.AT_MOST_ONCE)
    callsInPlace(combineRight, InvocationKind.AT_MOST_ONCE)
    (this@combine is Left && other is Left) holdsIn combineLeft
    (this@combine is Right && other is Right) holdsIn combineRight
  }
  return when (val one = this) {
    is Left -> when (other) {
      is Left -> Left(combineLeft(one.value, other.value))
      is Right -> one
    }

    is Right -> when (other) {
      is Left -> other
      is Right -> Right(combineRight(one.value, other.value))
    }
  }
}

public inline fun <B> map(f: (A) -> B): Option<B> {
  contract {
    callsInPlace(f, InvocationKind.AT_MOST_ONCE)
    (this@Option is Some) holdsIn f
  }
  return flatMap { a -> Some(f(a)) }
}

public inline fun <R> fold(ifEmpty: () -> R, ifSome: (A) -> R): R {
  contract {
    callsInPlace(ifEmpty, InvocationKind.AT_MOST_ONCE)
    callsInPlace(ifSome, InvocationKind.AT_MOST_ONCE)
    (this@Option is None) holdsIn ifEmpty
    (this@Option is Some) holdsIn ifSome
  }
  return when (this) {
    is None -> ifEmpty()
    is Some<A> -> ifSome(value)
  }
}

public inline fun <A, B, D> Ior<A, B>.flatMap(combine: (A, A) -> A, f: (B) -> Ior<A, D>): Ior<A, D> {
  contract {
    callsInPlace(combine, InvocationKind.AT_MOST_ONCE)
    callsInPlace(f, InvocationKind.AT_MOST_ONCE)
    (this@flatMap is Both) holdsIn combine
    (this@flatMap !is Left) holdsIn f
  }
  return when (this) {
    is Left -> this
    is Right -> f(value)
    is Both -> when (val r = f(rightValue)) {
      is Left -> Left(combine(this.leftValue, r.value))
      is Right -> Both(this.leftValue, r.value)
      is Both -> Both(combine(this.leftValue, r.leftValue), r.rightValue)
    }
  }
}

public inline fun <A, B, D> Ior<A, B>.handleErrorWith(combine: (B, B) -> B, f: (A) -> Ior<D, B>): Ior<D, B> {
  contract {
    callsInPlace(combine, InvocationKind.AT_MOST_ONCE)
    callsInPlace(f, InvocationKind.AT_MOST_ONCE)
    (this@handleErrorWith is Both) holdsIn combine
    (this@handleErrorWith !is Right) holdsIn f
  }
  return when (this) {
    is Left -> f(value)
    is Right -> this
    is Both -> when (val l = f(leftValue)) {
      is Left -> Both(l.value, this.rightValue)
      is Right -> Right(combine(this.rightValue, l.value))
      is Both -> Both(l.leftValue, combine(this.rightValue, l.rightValue))
    }
  }
}

fun JsonWriter.writeAny(value: Any?) {
  when (value) {
    null -> nullValue()

    is Map<*, *> -> {
      writeObject {
        value.forEach { (key, value) ->
          name(key.toString())
          writeAny(value)
        }
      }
    }

    is List<*> -> {
      writeArray {
        value.forEach {
          writeAny(it)
        }
      }
    }

    is Boolean -> value(value)
    is Int -> value(value)
    is Long -> value(value)
    is Double -> value(value)
    is JsonNumber -> value(value)
    is String -> value(value)
    else -> error("Cannot write $value of class '${value::class}' to Json")
  }
}

internal suspend fun OutgoingContent.observe(log: ByteWriteChannel): OutgoingContent = when (this) {
    is OutgoingContent.ByteArrayContent -> {
        log.writeFully(bytes())
        log.flushAndClose()
        this
    }
    is OutgoingContent.ReadChannelContent -> {
        val responseChannel = ByteChannel()
        val content = readFrom()

        content.copyToBoth(log, responseChannel)
        LoggedContent(this, responseChannel)
    }
    is OutgoingContent.WriteChannelContent -> {
        val responseChannel = ByteChannel()
        val content = toReadChannel()
        content.copyToBoth(log, responseChannel)
        LoggedContent(this, responseChannel)
    }
    is OutgoingContent.ContentWrapper -> copy(delegate().observe(log))
    is OutgoingContent.NoContent, is OutgoingContent.ProtocolUpgrade -> {
        log.flushAndClose()
        this
    }
}

@OptIn(DelicateCoroutinesApi::class, ExperimentalForeignApi::class)
internal fun WinHttpRequest.readBody(callContext: CoroutineContext): ByteReadChannel {
    return GlobalScope.writer(callContext) {
        val readBuffer = ByteArrayPool.borrow()
        try {
            while (callContext.isActive) {
                val availableBytes = queryDataAvailable()
                if (availableBytes <= 0) {
                    break
                }
                val bytesToRead = minOf(availableBytes, readBuffer.size)
                val readBytes = readBuffer.usePinned { dst ->
                    readData(dst, bytesToRead)
                }
                channel.writeFully(readBuffer, 0, readBytes)
                channel.flush()
            }
        } finally {
            ByteArrayPool.recycle(readBuffer)
        }
    }.channel
}

private fun mergeInterceptors(from: Pipeline<TSubject, TContext>) {
    if (interceptorsQuantity == 0) {
        setInterceptorsListFromAnotherPipeline(from)
    } else {
        resetInterceptorsList()
    }

    val fromPhases = from.phasesRaw
    fromPhases.forEach { fromPhaseOrContent ->
        val fromPhase = (fromPhaseOrContent as? PipelinePhase)
            ?: (fromPhaseOrContent as PhaseContent<*, *>).phase

        if (fromPhaseOrContent is PhaseContent<*, *> && !fromPhaseOrContent.isEmpty) {
            @Suppress("UNCHECKED_CAST")
            fromPhaseOrContent as PhaseContent<TSubject, TContext>

            fromPhaseOrContent.addTo(findPhase(fromPhase)!!)
            interceptorsQuantity += fromPhaseOrContent.size
        }
    }
}

internal inline fun Buffer.commonReadUtf8(byteCount: Long): String {
  require(byteCount >= 0 && byteCount <= Int.MAX_VALUE) { "byteCount: $byteCount" }
  if (size < byteCount) throw EOFException()
  if (byteCount == 0L) return ""

  val s = head!!
  if (s.pos + byteCount > s.limit) {
    // If the string spans multiple segments, delegate to readBytes().

    return readByteArray(byteCount).commonToUtf8String()
  }

  val result = s.data.commonToUtf8String(s.pos, s.pos + byteCount.toInt())
  s.pos += byteCount.toInt()
  size -= byteCount

  if (s.pos == s.limit) {
    head = s.pop()
    SegmentPool.recycle(s)
  }

  return result
}

private fun beforeValue() {
  when (peekScope()) {
    JsonScope.NONEMPTY_DOCUMENT -> throw IllegalStateException("JSON must have only one top-level value.")
    JsonScope.EMPTY_DOCUMENT -> replaceTop(JsonScope.NONEMPTY_DOCUMENT)
    JsonScope.EMPTY_ARRAY -> {
      replaceTop(JsonScope.NONEMPTY_ARRAY)
      newline()
    }
    JsonScope.NONEMPTY_ARRAY -> {
      sink.writeByte(','.code)
      newline()
    }
    JsonScope.DANGLING_NAME -> {
      sink.writeUtf8(separator)
      replaceTop(JsonScope.NONEMPTY_OBJECT)
    }
    else -> throw IllegalStateException("Nesting problem.")
  }
}

fun string(sink: BufferedSink, value: String) {
  val replacements = REPLACEMENT_CHARS
  sink.writeByte('"'.code)
  var last = 0
  val length = value.length
  for (i in 0 until length) {
    val c = value[i]
    var replacement: String?
    if (c.code < 128) {
      replacement = replacements[c.code]
      if (replacement == null) {
        continue
      }
    } else if (c == '\u2028') {
      replacement = "\\u2028"
    } else if (c == '\u2029') {
      replacement = "\\u2029"
    } else {
      continue
    }
    if (last < i) {
      sink.writeUtf8(value, last, i)
    }
    sink.writeUtf8(replacement)
    last = i + 1
  }
  if (last < length) {
    sink.writeUtf8(value, last, length)
  }
  sink.writeByte('"'.code)
}

override fun peek(): JsonReader.Token {
  return when (peekIfNone()) {
    PEEKED_BEGIN_OBJECT -> JsonReader.Token.BEGIN_OBJECT
    PEEKED_END_OBJECT -> JsonReader.Token.END_OBJECT
    PEEKED_BEGIN_ARRAY -> JsonReader.Token.BEGIN_ARRAY
    PEEKED_END_ARRAY -> JsonReader.Token.END_ARRAY
    PEEKED_SINGLE_QUOTED_NAME, PEEKED_DOUBLE_QUOTED_NAME, PEEKED_UNQUOTED_NAME -> JsonReader.Token.NAME
    PEEKED_TRUE, PEEKED_FALSE -> JsonReader.Token.BOOLEAN
    PEEKED_NULL -> JsonReader.Token.NULL
    PEEKED_SINGLE_QUOTED, PEEKED_DOUBLE_QUOTED, PEEKED_UNQUOTED, PEEKED_BUFFERED -> JsonReader.Token.STRING
    PEEKED_LONG -> JsonReader.Token.LONG
    PEEKED_NUMBER -> JsonReader.Token.NUMBER
    PEEKED_EOF -> JsonReader.Token.END_DOCUMENT
    else -> throw AssertionError()
  }
}

override fun nextString(): String? {
  val result = when (peekIfNone()) {
    PEEKED_UNQUOTED -> nextUnquotedValue()
    PEEKED_DOUBLE_QUOTED -> nextQuotedValue(DOUBLE_QUOTE_OR_SLASH)
    PEEKED_SINGLE_QUOTED -> nextQuotedValue(SINGLE_QUOTE_OR_SLASH)
    PEEKED_BUFFERED -> peekedString?.also { peekedString = null }
    PEEKED_LONG -> peekedLong.toString()
    PEEKED_NUMBER -> buffer.readUtf8(peekedNumberLength.toLong())
    else -> throw JsonDataException("Expected a string but was ${peek()} at path ${getPathAsString()}")
  }
  peeked = PEEKED_NONE
  pathIndices[stackSize - 1]++
  return result
}

@ApolloInternal
fun JsonReader.readAny(): ApolloJsonElement {
  return when (val token = peek()) {
    JsonReader.Token.NULL -> nextNull()
    JsonReader.Token.BOOLEAN -> nextBoolean()
    JsonReader.Token.LONG, JsonReader.Token.NUMBER -> guessNumber()
    JsonReader.Token.STRING -> nextString()
    JsonReader.Token.BEGIN_OBJECT -> {
      beginObject()
      val result = mutableMapOf<String, Any?>()
      while (hasNext()) {
        result.put(nextName(), readAny())
      }
      endObject()
      result
    }
    JsonReader.Token.BEGIN_ARRAY -> {
      beginArray()
      val result = mutableListOf<Any?>()
      while (hasNext()) {
        result.add(readAny())
      }
      endArray()
      result
    }
    else -> error("unknown token $token")
  }
}

private fun advanceIterator() {
  if (stackSize == 0) {
    peekedToken = JsonReader.Token.END_DOCUMENT
    return
  }

  val currentIterator = iteratorStack[stackSize - 1]!!

  if (path[stackSize - 1] is Int) {
    path[stackSize - 1] = (path[stackSize - 1] as Int) + 1
  }

  if (currentIterator.hasNext()) {
    val next = currentIterator.next()
    peekedData = next

    peekedToken = when (next) {
      is Map.Entry<*, *> -> JsonReader.Token.NAME
      else -> anyToToken(next)
    }
  } else {
    peekedToken = if (path[stackSize - 1] is Int) {
      JsonReader.Token.END_ARRAY
    } else {
      JsonReader.Token.END_OBJECT
    }
  }
}

override fun nextDouble(): Double {
  when (peek()) {
    JsonReader.Token.STRING,
    JsonReader.Token.NUMBER,
    JsonReader.Token.LONG,
    -> Unit
    else -> {
      throw JsonDataException("Expected a Double but was ${peek()} at path ${getPathAsString()}")
    }
  }

  return when (val value = peekedData) {
    is Int -> value.toDouble()
    is Long -> value.toDoubleExact()
    is Double -> value
    is String -> value.toDouble()
    is JsonNumber -> value.value.toDouble()
    else -> error("Expected a Double but got $value instead")
  }.also {
    advanceIterator()
  }
}

