override fun visitClassOrObject(classOrObject: KtClassOrObject) {
    if (classOrObject.getSuperNames().contains("Iterator")) {
        val hasNextMethod = classOrObject.findFunctionByName("hasNext")
        if (hasNextMethod != null && callsNextMethod(hasNextMethod)) {
            report(
                Finding(
                    Entity.atName(classOrObject),
                    "Calling hasNext() on an Iterator should " +
                        "have no side-effects. Calling next() is a side effect."
                )
            )
        }
    }
    super.visitClassOrObject(classOrObject)
}

private fun KaSession.isExpressionUsedOnSameOrNextLine(expression: KtExpression): Boolean {
    val parent = expression.getParentOfTypes(
        true,
        KtQualifiedExpression::class.java,
        KtProperty::class.java
    )

    return when (parent) {
        is KtQualifiedExpression -> {
            parent.doesEndWithUse()
        }

        is KtProperty -> {
            parent.siblings(forward = true, withItself = false).filter {
                it.text.isNotBlank()
            }.mapNotNull {
                it.parentsWithSelf
                    .firstOrNull { element -> element !is KtParenthesizedExpression } as? KtQualifiedExpression
            }.filter {
                it.doesEndWithUse()
            }.any {
                it.receiverExpression.text == parent.name
            }
        }

        else -> {
            false
        }
    }
}

