@OptIn(ExperimentalForeignApi::class)
    private suspend fun writeBodyChunk(readBuffer: ByteArray, length: Int) {
        // Write chunk length
        val chunkStart = "${length.toString(16)}\r\n".toByteArray()
        chunkStart.usePinned { src ->
            request.writeData(src, chunkStart.size)
        }
        // Write chunk data
        readBuffer.usePinned { src ->
            request.writeData(src, length)
        }
        // Write chunk ending
        chunkEnd.usePinned { src ->
            request.writeData(src, chunkEnd.size)
        }
    }

@Suppress("UNCHECKED_CAST")
private fun Map<String, Any>.toBooleanExpression(): BooleanExpression<BTerm> {
  return when (this.get("operator")) {
    "and" -> {
      BooleanExpression.And((this.get("operands") as List<Map<String, Any>>).map { it.toBooleanExpression() }.toSet())
    }

    "or" -> {
      BooleanExpression.Or((this.get("operands") as List<Map<String, Any>>).map { it.toBooleanExpression() }.toSet())
    }

    "not" -> {
      BooleanExpression.Not((this.get("operands") as List<Map<String, Any>>).map { it.toBooleanExpression() }.single())
    }

    "element" -> {
      BooleanExpression.Element((this.get("element") as Map<String, Any?>).toBTerm())
    }

    "true" -> BooleanExpression.True
    "false" -> BooleanExpression.False
    else -> error("unrecognized operator in $this")
  }
}

internal fun List<Issue>.group(
    issueSeverities: Map<String, IssueSeverity>,
): IssueGroup {
  val ignored = mutableListOf<Issue>()
  val warnings = mutableListOf<Issue>()
  val errors = mutableListOf<Issue>()

  forEach {
    val name = it.javaClass.simpleName
    val severity = issueSeverities.get(name) ?: IssueSeverity.Error

    when (severity) {
      IssueSeverity.Ignore -> ignored.add(it)
      IssueSeverity.Warn -> warnings.add(it)
      IssueSeverity.Error -> errors.add(it)
    }
  }

  return IssueGroup(ignored, warnings, errors)
}

private fun IrDataBuilder.mapTypeSpec(): TypeSpec {
  return TypeSpec
      .classBuilder(simpleName)
      .addModifiers(Modifier.PUBLIC)
      .superclass(JavaClassNames.ObjectMap)
      .addSuperinterfaces(
          superTypes.map {
            ClassName.get(packageName, dataMapName(it, false, layout))
          }
      )
      .apply {
        if (isAbstract) {
          addSuperinterface(ClassName.get(packageName, dataMapName(name, false, layout)))
        }
      }
      .addMethod(
          MethodSpec.constructorBuilder()
              .addModifiers(Modifier.PUBLIC)
              .addParameter(JavaClassNames.MapOfStringToObject, __fields)
              .addStatement("super(${__fields})")
              .build()
      )
      .build()
}

private fun nullableAdapterCodeBlock(typeName: String): CodeBlock {
  val className: ClassName
  val adapterNamePrefix: String
  when (nullableFieldStyle) {
    JavaNullable.APOLLO_OPTIONAL -> {
      // Ex: Adapters.ApolloOptionalStringAdapter
      className = JavaClassNames.Adapters
      adapterNamePrefix = "ApolloOptional"
    }

    JavaNullable.JAVA_OPTIONAL, JavaNullable.GUAVA_OPTIONAL -> {
      // Ex: OptionalAdapters.OptionalStringAdapter
      className = resolveJavaOptionalAdapters()
      adapterNamePrefix = "Optional"
    }

    else -> {
      // Ex: Adapters.NullableStringAdapter
      className = JavaClassNames.Adapters
      adapterNamePrefix = "Nullable"
    }
  }
  val adapterName = "$adapterNamePrefix${typeName}Adapter"
  return CodeBlock.of("$T.$L", className, adapterName)
}

internal fun serializeVariablesMethodSpec(
    adapterClassName: TypeName?,
    emptyMessage: String,
): MethodSpec {

  val body = if (adapterClassName == null) {
    CodeBlock.of("// $emptyMessage\n")
  } else {
    CodeBlock.of("$T.INSTANCE.$serializeVariables($writer, this, $customScalarAdapters, $withDefaultValues);\n", adapterClassName)
  }
  return MethodSpec.methodBuilder(serializeVariables)
      .addModifiers(Modifier.PUBLIC)
      .addException(JavaClassNames.IOException)
      .addAnnotation(JavaClassNames.Override)
      .addParameter(JavaClassNames.JsonWriter, writer)
      .addParameter(JavaClassNames.CustomScalarAdapters, customScalarAdapters)
      .addParameter(TypeName.BOOLEAN, withDefaultValues)
      .addCode(body)
      .build()
}
